mapper.select:
/* CourtLcMgmtMapper.getCourtLcMgmtList */
SELECT MST.LC_SEQ, MST.LC_NUM, FN_GET_CODENM('MSP0015', MST.LC_STAT_CD) AS LC_STAT_CD, MST.CSTMR_NAME, CRYPTO_AES256.DEC_AES(MST.CSTMR_RRN) AS CSTMR_RRN, SUM(DTL.UNPD_PRC) AS UNPD_PRC, SUM(DTL.INST_PRC) AS INST_PRC, SUM(DTL.UNPD_PRC) + SUM(DTL.INST_PRC) AS TOTAL, (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = MST.ISSUE_ID) AS ISSUE_ID, CASE MST.LC_STAT_CD WHEN '2' THEN TO_CHAR(MST.ISSUE_DTTM, 'YYYY-MM-DD HH24:MI:SS') ELSE '' END AS ISSUE_DTTM, DECODE(MST.LC_STAT_CD, 2, '가능', '불가능') AS PRINT_YN, (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = MST.REGST_ID) AS REGST_ID, TO_CHAR(MST.REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS REGST_DTTM, (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = MST.RVISN_ID) AS RVISN_ID, TO_CHAR(MST.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM, MST.CSTMR_ADDR FROM MSP_LC_MST MST, MSP_LC_DTL DTL WHERE MST.LC_SEQ = DTL.LC_SEQ (+)
AND TO_CHAR(MST.REGST_DTTM, 'YYYYMMDDHH24MISS') BETWEEN #{strtDt} || '000000' AND #{endDt} || '235959'
AND MST.CSTMR_NAME LIKE '%' || #{searchVal} || '%'
AND MST.CSTMR_RRN = #{searchRrn}
AND MST.LC_STAT_CD = #{lcStatCd}
GROUP BY MST.LC_SEQ, MST.LC_NUM, MST.LC_STAT_CD, MST.CSTMR_NAME,MST.CSTMR_RRN, MST.ISSUE_ID,TO_CHAR(MST.ISSUE_DTTM, 'YYYY-MM-DD HH24:MI:SS'), MST.REGST_ID, TO_CHAR(MST.REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS'), MST.RVISN_ID, TO_CHAR(MST.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS'),MST.CSTMR_ADDR ORDER BY MST.LC_SEQ DESC

/* courtLcMgmtMapper.getCourtLcMgmtListByExcel */ SELECT MST.LC_SEQ, MST.LC_NUM, FN_GET_CODENM('MSP0015', MST.LC_STAT_CD) AS LC_STAT_CD, MST.CSTMR_NAME, CRYPTO_AES256.DEC_AES(MST.CSTMR_RRN) AS CSTMR_RRN, SUM(DTL.UNPD_PRC) AS UNPD_PRC, SUM(DTL.INST_PRC) AS INST_PRC, SUM(DTL.UNPD_PRC) + SUM(DTL.INST_PRC) AS TOTAL, (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = MST.ISSUE_ID) AS ISSUE_ID, CASE MST.LC_STAT_CD WHEN '2' THEN TO_CHAR(MST.ISSUE_DTTM, 'YYYY-MM-DD HH24:MI:SS') ELSE '' END AS ISSUE_DTTM, DECODE(MST.LC_STAT_CD, 2, '가능', '불가능') AS PRINT_YN, (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = MST.REGST_ID) AS REGST_ID, TO_CHAR(MST.REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS REGST_DTTM, (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = MST.RVISN_ID) AS RVISN_ID, TO_CHAR(MST.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM, MST.CSTMR_ADDR FROM MSP_LC_MST MST, MSP_LC_DTL DTL WHERE MST.LC_SEQ = DTL.LC_SEQ (+)
AND TO_CHAR(MST.REGST_DTTM, 'YYYYMMDDHH24MISS') BETWEEN #{strtDt} || '000000' AND #{endDt} || '235959'
AND MST.CSTMR_NAME LIKE '%' || #{searchVal} || '%'
AND MST.CSTMR_RRN = #{searchRrn}
AND MST.LC_STAT_CD = #{lcStatCd}
GROUP BY MST.LC_SEQ, MST.LC_NUM, MST.LC_STAT_CD, MST.CSTMR_NAME,MST.CSTMR_RRN, MST.ISSUE_ID,TO_CHAR(MST.ISSUE_DTTM, 'YYYY-MM-DD HH24:MI:SS'), MST.REGST_ID, TO_CHAR(MST.REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS'), MST.RVISN_ID, TO_CHAR(MST.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS'),MST.CSTMR_ADDR ORDER BY MST.LC_SEQ DESC

        /* courtLcMgmtMapper.checkLcMst */
		SELECT	COUNT(*)
	    FROM	MSP_LC_MST
		WHERE	CSTMR_RRN = #{cstmrRrn}
		AND		LC_STAT_CD IN ('1', '2')

        /* courtLcMgmtMapper.checkLcSeq */
		SELECT	COUNT(*)
	    FROM	MSP_LC_MST
		WHERE	LC_SEQ = #{lcMstSeq}

mapper.insert:
/* CourtLcMgmtMapper.insertLcMst */
INSERT INTO MSP_LC_MST
(
    LC_SEQ
    , LC_STAT_CD
    , CSTMR_NAME
    , CSTMR_RRN
    , CSTMR_ADDR
    , REGST_ID
    , REGST_DTTM
    , RVISN_ID
    , RVISN_DTTM
)
VALUES
(
    #{lcMstSeq}
    , '1'
    , #{cstmrName}
    , #{cstmrRrn}
    , #{cstmrAddr}
    , #{sessionUserId}
    , SYSDATE
    , #{sessionUserId}
    , SYSDATE
)

/* CourtLcMgmtMapper.insertLcDtl */
INSERT INTO MSP_LC_DTL
(
    LC_DTL_SEQ
    , LC_SEQ
    , MOBILE_NO
    , OPEN_DT
    , UNPD_PRC
    , INST_PRC
    , SUM_PRC
    , REGST_ID
    , REGST_DTTM
    , RVISN_ID
    , RVISN_DTTM
)
VALUES
(
    SEQ_LC_DTL.NEXTVAL
    , #{lcMstSeq}
    , #{contactNum}
    , #{openDt}
    , #{unpdPrc}
    , #{instPrc}
    , #{totalPrc}
    , #{sessionUserId}
    , SYSDATE
    , #{sessionUserId}
    , SYSDATE
)

mapper.delete:
/* CourtLcMgmtMapper.deleteLcDtl */
DELETE FROM MSP_LC_DTL
WHERE LC_DTL_SEQ = #{lcDtlSeq}

mapper.update:
     /* CourtLcMgmtMapper.issueLcMst */
     UPDATE   MSP_LC_MST
     SET      LC_NUM = '부채-' || TO_CHAR(SYSDATE, 'YYYYMMDD') || TRIM(TO_CHAR(#{maxLcNumNvl}, '0000'))
			   , LC_STAT_CD = '2'
            , ISSUE_ID = #{sessionUserId}
            , ISSUE_DTTM = SYSDATE
            , RVISN_ID = #{sessionUserId}
            , RVISN_DTTM = SYSDATE
     WHERE    LC_SEQ = #{lcMstSeq}

/* CourtLcMgmtMapper.discardLcMst */
UPDATE	 MSP_LC_MST
SET		 LC_STAT_CD = '3'
		,RVISN_ID = #{sessionUserId}
		,RVISN_DTTM = SYSDATE
WHERE	 LC_SEQ = #{lcMstSeq}
